void updateWindowSize(void)
    /* getWindowSize's contract is replaced at the call site, so its precondition
     * (rk_idx == 0, used by the scripted read() model on the terminal-query path)
     * is asserted here; propagate it as updateWindowSize's own precondition. */
    __CPROVER_requires(rk_idx == 0)
    __CPROVER_assigns(E.screenrows, E.screencols, rk_idx)
    /* The normal-return line `E.screenrows -= 2` is reached only when
     * getWindowSize succeeded (returned 0); its contract guarantees a successful
     * query leaves a non-zero column count in *cols == E.screencols.  The mutant
     * that flips `== -1` to `!= -1` instead reaches this point only on FAILURE
     * (return -1), where the column count is unconstrained and may be 0 -- so this
     * postcondition holds for the original yet kills that mutant. */
    __CPROVER_ensures(E.screencols != 0)
{
    if (getWindowSize(STDIN_FILENO,STDOUT_FILENO,
                      &E.screenrows,&E.screencols) == -1) {
        perror("Unable to query the screen for size (columns / rows)");
        exit(1);
    }
    E.screenrows -= 2; /* Get room for status bar. */
}

